// Format Slack message based on event type
const slackConfig = $('Get Slack Config').first().json[0];
const payload = $('Notification Trigger').first().json.body;
const eventType = payload.event_type;
const data = payload.data || {};

let blocks = [];
let channel = slackConfig.default_channel || '#callengo-notifications';

switch (eventType) {
  case 'call.completed':
    blocks = [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Call Completed* :phone:\n*Contact:* ${data.contact_name || 'Unknown'}\n*Duration:* ${data.duration || 0}s\n*Agent:* ${data.agent_name || data.agent_type || 'Unknown'}`
        }
      },
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Summary:* ${data.summary || 'No summary available'}`
        }
      }
    ];
    break;

  case 'appointment.confirmed':
    blocks = [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Appointment Confirmed* :white_check_mark:\n*Contact:* ${data.contact_name || 'Unknown'}\n*Date:* ${data.appointment_time || 'Unknown'}`
        }
      }
    ];
    break;

  case 'appointment.rescheduled':
    blocks = [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Appointment Rescheduled* :calendar:\n*Contact:* ${data.contact_name || 'Unknown'}\n*New Time:* ${data.new_datetime || 'TBD'}`
        }
      }
    ];
    break;

  case 'appointment.no_show':
    blocks = [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*No-Show Risk* :warning:\n*Contact:* ${data.contact_name || 'Unknown'}\n*Appointment:* ${data.appointment_time || 'Unknown'}`
        }
      }
    ];
    channel = slackConfig.alert_channel || channel;
    break;

  case 'lead.qualified':
    blocks = [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Hot Lead!* :fire:\n*Contact:* ${data.contact_name || 'Unknown'}\n*Score:* ${data.score || 0}/100\n*Next:* ${data.next_action || 'Follow up'}`
        }
      }
    ];
    channel = slackConfig.sales_channel || channel;
    break;

  case 'payment.failed':
    blocks = [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Payment Failed* :rotating_light:\n*Customer:* ${data.customer || 'Unknown'}\n*Amount:* $${((data.amount || 0) / 100).toFixed(2)}`
        }
      }
    ];
    channel = slackConfig.alert_channel || channel;
    break;

  case 'campaign.completed':
    blocks = [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*Campaign Completed* :checkered_flag:\n*Name:* ${data.campaign_name || 'Unknown'}\n*Calls Made:* ${data.total_calls || 0}\n*Success Rate:* ${data.success_rate || 'N/A'}`
        }
      }
    ];
    break;

  default:
    blocks = [
      {
        type: 'section',
        text: {
          type: 'mrkdwn',
          text: `*${eventType}*\n${JSON.stringify(data, null, 2).substring(0, 500)}`
        }
      }
    ];
}

return [{
  json: {
    channel: channel,
    access_token: slackConfig.access_token,
    blocks: blocks,
    text: `Callengo: ${eventType}`
  }
}];
